questionvariables.text:
/* Randomized movement distances */
d1: 4 + rand(5);        /* First leg (North) 4-8 km */
d2: 3 + rand(4);        /* Second leg (East) 3-6 km */

/* Calculated Resultants */
total_dist: d1 + d2;
displacement_mag: float(sqrt(d1^2 + d2^2));

/* Correct Answers rounded for STACK */
ta1: total_dist;
ta2: float(round(displacement_mag * 100) / 100);

/* Heading/Bearing Calculation */
bearing: float(round((180/float(%pi)) * atan(d2/d1) * 10) / 10);
